definition.script:
pipeline {
    agent {
        label 'jenkins-jenkins-agent'
    }

    environment {
        REGISTRY = "192.168.56.129:30002"
        IMAGE = "library/nginx"
        TAG = "test"
    }

    stages {

        stage('Pull Base Image') {
            steps {
                container('docker') {
                    sh 'docker pull nginx'
                }
            }
        }

        stage('Tag Image') {
            steps {
                container('docker') {
                    sh 'docker tag nginx $REGISTRY/$IMAGE:$TAG'
                }
            }
        }

        stage('Push to Harbor') {
            steps {
                container('docker') {
                    sh 'docker push $REGISTRY/$IMAGE:$TAG'
                }
            }
        }

        stage('Scan with Trivy') {
            steps {
                container('docker') {
                    sh '''
                    trivy image --exit-code 1 --severity CRITICAL,HIGH $REGISTRY/$IMAGE:$TAG
                    '''
                }
            }
        }

        stage('Get Digest') {
            steps {
                container('docker') {
                    script {
                        env.DIGEST = sh(
                            script: "docker inspect --format='{{index .RepoDigests 0}}' $REGISTRY/$IMAGE:$TAG",
                            returnStdout: true
                        ).trim()
                    }
                }
            }
        }

        stage('Sign Image') {
            steps {
                container('docker') {
                    sh 'cosign sign --key cosign.key $DIGEST'
                }
            }
        }

        stage('Verify Signature') {
            steps {
                container('docker') {
                    sh 'cosign verify --key cosign.pub $DIGEST'
                }
            }
        }

        stage('Deploy to Kubernetes') {
            steps {
                sh '''
                kubectl set image deployment/demo-app demo-app=$DIGEST
                '''
            }
        }
        stage('Security Gate') {
            steps {
                container('docker') {
                    sh 'cosign verify --key cosign.pub $DIGEST'
                }
            }
        }
    }
}
